import java.io.*;
import java.util.*;

public class Main {
    static long[] solveCase(int n, int q, int[] sold, int[][] queries) {
        // your code here — return one total per question, in order
        return new long[q];
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int t = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (t-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int q = Integer.parseInt(st.nextToken());
            int[] sold = new int[n];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < n; i++) sold[i] = Integer.parseInt(st.nextToken());
            int[][] queries = new int[q][2];
            for (int i = 0; i < q; i++) {
                st = new StringTokenizer(br.readLine());
                queries[i][0] = Integer.parseInt(st.nextToken());
                queries[i][1] = Integer.parseInt(st.nextToken());
            }
            for (long ans : solveCase(n, q, sold, queries)) out.append(ans).append('\n');
        }
        System.out.print(out);
    }
}

